metadata.codeSnippet:
import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";

export async function main() {
  const discovery = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "find_moderate_probability_bets",
    args: {
      minPrice: 0.4,
      maxPrice: 0.6,
      minLiquidity: 1000000,
      limit: 10,
      sortBy: "liquidity",
      category: "all"
    }
  });

  const opportunities = Array.isArray(discovery?.opportunities) ? discovery.opportunities : [];
  const shortlist = opportunities.slice(0, 5);

  const liquidityChecks = await callMcpSkillsParallel({
    label: "liquidity-check-shortlist",
    calls: shortlist.map((m, i) => ({
      key: `m${i}`,
      toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
      toolName: "analyze_market_liquidity",
      args: {
        conditionId: m.conditionId,
        slug: m.slug
      }
    }))
  });

  const assessed = shortlist.map((market, idx) => {
    const entry = liquidityChecks.results.find((r) => r.key === `m${idx}`);
    const data = entry && entry.status === "fulfilled" ? entry.value : null;

    const sell5k = data && data.whaleCost && data.whaleCost.sell5k ? data.whaleCost.sell5k : null;
    const sell1k = data && data.whaleCost && data.whaleCost.sell1k ? data.whaleCost.sell1k : null;
    const sell10k = data && data.whaleCost && data.whaleCost.sell10k ? data.whaleCost.sell10k : null;

    return {
      market: market.market,
      url: market.url,
      slug: market.slug,
      conditionId: market.conditionId,
      currentPrice: market.currentPrice,
      liquidity: market.liquidity,
      volume24h: market.volume24h,
      opportunityType: market.opportunityType,
      suggestedSide: market.suggestedSide,
      liquidityScore: data ? data.liquidityScore : null,
      spread: data ? data.spread : null,
      whaleCost: data ? data.whaleCost : null,
      canLikelyHandle5k: !!(sell5k && typeof sell5k === "object" && (sell5k.slippagePercent === undefined || sell5k.slippagePercent <= 5)),
      rankSignal: {
        sell1k: sell1k && typeof sell1k === "object" ? sell1k : null,
        sell5k: sell5k && typeof sell5k === "object" ? sell5k : null,
        sell10k: sell10k && typeof sell10k === "object" ? sell10k : null
      }
    };
  });

  assessed.sort((a, b) => {
    const score = (x) => {
      const liq = typeof x.liquidity === "number" ? x.liquidity : 0;
      const spreadPenalty = typeof x.spread === "number" ? x.spread * 100000 : 0;
      const slippagePenalty = x.whaleCost && x.whaleCost.sell5k && typeof x.whaleCost.sell5k.slippagePercent === "number"
        ? x.whaleCost.sell5k.slippagePercent * 10000
        : 50000;
      return liq - spreadPenalty - slippagePenalty;
    };
    return score(b) - score(a);
  });

  return {
    filters: {
      minPrice: 0.4,
      maxPrice: 0.6,
      minLiquidity: 1000000,
      positionSizeUsd: 5000
    },
    discoverySummary: discovery?.summary ?? null,
    totalMatches: Array.isArray(opportunities) ? opportunities.length : 0,
    rankedTradableMarkets: assessed.map((x, i) => ({
      rank: i + 1,
      market: x.market,
      url: x.url,
      currentPrice: x.currentPrice,
      liquidity: x.liquidity,
      volume24h: x.volume24h,
      liquidityScore: x.liquidityScore,
      canLikelyHandle5k: x.canLikelyHandle5k,
      spread: x.spread,
      sell5k: x.whaleCost && x.whaleCost.sell5k ? x.whaleCost.sell5k : null
    })),
    partialFailures: liquidityChecks.results
      .filter((r) => r.status === "rejected")
      .map((r) => ({ key: r.key, error: r.error })),
    note: "Ranked using past-query tool data; slippage and liquidity values are from that fetched snapshot, not live current-time guarantees."
  };
}

