import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const result = await callMcpSkill({
    toolId,
    toolName: "find_arbitrage_opportunities",
    args: {
      category: "politics",
      limit: 20
    }
  });

  const arbitrageOpportunities = Array.isArray(result?.arbitrageOpportunities)
    ? result.arbitrageOpportunities
    : [];
  const wideSpreadMarkets = Array.isArray(result?.wideSpreadMarkets)
    ? result.wideSpreadMarkets
    : [];

  const passiveOrderCandidates = wideSpreadMarkets
    .filter((m) => typeof m?.spread === "number")
    .map((m) => ({
      market: m.market,
      url: m.url,
      spread: m.spread,
      midPrice: m.midPrice,
      spreadPercent: m.spreadPercent,
      passiveOrderAngle:
        m.spread >= 0.05
          ? "wide spread; consider maker/passive orders"
          : "tight spread; less compelling for passive order capture"
    }));

  const verifiedArbitrage = arbitrageOpportunities.map((a) => ({
    market: a.market,
    url: a.url,
    totalCost: a.totalCost,
    buyYesAt: a.buyYesAt,
    buyNoAt: a.buyNoAt,
    edgePercent: a.edgePercent,
    potentialEdge: a.potentialEdge,
    note: a.note
  }));

  return {
    summary: result?.summary,
    methodology: result?.methodology,
    fetchedAt: result?.fetchedAt,
    verifiedArbitrage,
    wideSpreadMarkets,
    passiveOrderCandidates
  };
}

